    max_value = 0

    for i in range(1, 2**n + 1):
        binary = bin(i)[2:].zfill(n)
        total_weight = 0
        total_value = 0

        for j in range(n):
            if binary[j] == '1':
                total_weight += weights[j]
                total_value += values[j]

        if total_weight <= capacity and total_value > max_value:
