import heapq
from collections import defaultdict

class Node:
    def __init__(self, char, freq):
        self.char = char
        self.freq = freq
        self.left = None
        self.right = None

    def __lt__(self, other):
        return self.freq < other.freq

def calculate_frequency(input_string):
    frequency = defaultdict(int)
    for char in input_string:
        frequency[char] += 1
    return frequency

def build_huffman_tree(frequency):
    heap = []
    for char, freq in frequency.items():
        node = Node(char, freq)
        heapq.heappush(heap, node)

    while len(heap) != 1:
        node1 = heapq.heappop(heap)
        node2 = heapq.heappop(heap)

        merged_node = Node(None, node1.freq + node2.freq)
        merged_node.left = node1
        merged_node.right = node2

        heapq.heappush(heap, merged_node)

    return heap[0]

def generate_prefix_codes(node, prefix="", codes={}):
    if node.char is not None:
        codes[node.char] = prefix
    if node.left:
        generate_prefix_codes(node.left, prefix + "0", codes)
    if node.right:
        generate_prefix_codes(node.right, prefix + "1", codes)

def huffman_encoding(input_string):
    frequency = calculate_frequency(input_string)
    huffman_tree = build_huffman_tree(frequency)
    prefix_codes = generate_prefix_codes(huffman_tree)

    encoded_string = ""
    for char in input_string:
        encoded_string += prefix_codes[char]

    return encoded_string, huffman_tree

def huffman_decoding(encoded_string, huffman_tree):
    decoded_string = ""
    current_node = huffman_tree

    for bit in encoded_string:
        if bit == "0":
            current_node = current_node.left
        else:
            current_node = current_node.right

        if current_node.char is not None:
            decoded_string += current_node.char
            current_node = huffman_tree

    return decoded_string

def main():
    input_string = input("Enter the input string or file path: ")
    encoded_string, huffman_tree = huffman_encoding(input_string)
    print("Encoded String:", encoded_string)

    decoded_string = huffman_decoding(encoded_string, huffman_tree)
    print("Decoded String:", decoded_string)

if __name__ == "__main__":
    main()
