def max_revenue(products, discount_limit):
    n = len(products)
    dp = [[0] * (discount_limit + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(1, discount_limit + 1):
            discount = products[i - 1][1]
            revenue = products[i - 1][0]
            if discount > j:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - discount] + revenue)

    return dp[n][discount_limit]


def optimal_discounts(products, discount_limit):
    n = len(products)
    dp = [[0] * (discount_limit + 1) for _ in range(n + 1)]
    path = [[] for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(1, discount_limit + 1):
            discount = products[i - 1][1]
            revenue = products[i - 1][0]
            if discount > j:
                dp[i][j] = dp[i - 1][j]
            else:
                if dp[i - 1][j] > dp[i - 1][j - discount] + revenue:
                    dp[i][j] = dp[i - 1][j]
                else:
                    dp[i][j] = dp[i - 1][j - discount] + revenue
                    path[i].append(products[i - 1])

    return dp[n][discount_limit], path[n]


