#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

using namespace std;

struct Route {
    int id;
    int capacity;
    int distance;
};

struct Result {
    int load;
    int distance;
};

int dp(vector<Route>& routes, vector<vector<int>>& memo, int load, int idx) {
    if (load == 0)
        return 0;
    if (idx == routes.size())
        return numeric_limits<int>::max();

    if (memo[idx][load] != -1)
        return memo[idx][load];

    int take = numeric_limits<int>::max();
    int skip = dp(routes, memo, load, idx + 1);

    for (int i = 0; i <= routes[idx].capacity; i++) {
        if (load - i < 0)
            continue;

        int newLoad = load - i;
        int newDistance = routes[idx].distance + dp(routes, memo, newLoad, idx + 1);
        take = min(take, newDistance);
    }

    memo[idx][load] = take;
    return take;
}

int optimizeRoute(vector<Route>& routes) {
    int n = routes.size();
    vector<vector<int>> memo(n + 1, vector<int>(routes[routes.size() - 1].capacity + 1, -1));

    int result = dp(routes, memo, routes[routes.size() - 1].capacity, 0);

    for (int i = 0; i <= routes[routes.size() - 1].capacity; i++) {
        if (dp(routes, memo, i, 0) != numeric_limits<int>::max())
            result = min(result, dp(routes, memo, i, 0));
    }

    return result;
}

int main() {
    vector<Route> routes = {{1, 10, 20}, {2, 15, 30}, {3, 20, 40}};
    int result = optimizeRoute(routes);
    cout << "Minimum fuel consumption: " << result << endl;
    return 0;
}
