public class TextAlignment {
    private static final int INF = Integer.MAX_VALUE;
    private static final int MAX_WIDTH = 100;

    public static int calculateAlignmentCost(String paragraph, int[] wordLengths, int[] hyphenationRules, int[] mandatoryBreaks) {
        int n = wordLengths.length;
        int[][] memo = new int[n + 1][MAX_WIDTH + 1];

        return dfs(paragraph, wordLengths, hyphenationRules, mandatoryBreaks, memo, 0, 0);
    }

    private static int dfs(String paragraph, int[] wordLengths, int[] hyphenationRules, int[] mandatoryBreaks, int[][] memo, int i, int cost) {
        if (i == paragraph.length())
            return cost;

        if (memo[i][cost] != INF)
            return memo[i][cost];

        int minCost = INF;

        for (int j = 0; j <= Math.min(cost + wordLengths[i], MAX_WIDTH); j++) {
            if (i + 1 < paragraph.length()) {
                int nextCost = dfs(paragraph, wordLengths, hyphenationRules, mandatoryBreaks, memo, i + 1, cost + j + (hyphenationRules[i] == 0 ? 0 : 1));
                if (i + 1 < paragraph.length() && mandatoryBreaks[i] == 0 && (j == 0 || wordLengths[i] > MAX_WIDTH - j)) {
                    nextCost += wordLengths[i];
                }
                minCost = Math.min(minCost, nextCost);
            }
        }

        memo[i][cost] = minCost;
        return minCost;
    }

    public static void main(String[] args) {
        String paragraph = "Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.";
        int[] wordLengths = {10, 15, 8, 12, 18, 10, 14};
        int[] hyphenationRules = {0, 1, 0, 0, 1, 0, 0};
        int[] mandatoryBreaks = {0, 1, 0, 0, 1, 0, 0};

        int alignmentCost = calculateAlignmentCost(paragraph, wordLengths, hyphenationRules, mandatoryBreaks);
        System.out.println("Optimal text alignment cost: " + alignmentCost);
    }
}
