// Function to find the maximum subarray sum
int findMaxSubarraySum(const std::vector<int>& arr) {
    if (arr.empty()) {
        return 0;
    }

    int maxSum = arr[0];
    int currentSum = arr[0];

    for (int i = 1; i < arr.size(); ++i) {
        currentSum = std::max(arr[i], currentSum + arr[i]);
        maxSum = std::max(maxSum, currentSum);
    }

    return maxSum;
}

// Function to find the peak operational intervals
std::vector<std::pair<int, int>> findPeakOperationalIntervals(const std::vector<int>& arr) {
    int maxSum = findMaxSubarraySum(arr);
    int start = 0;
    int end = 0;
    int tempStart = 0;

    for (int i = 0; i < arr.size(); ++i) {
        if (arr[i] < 0) {
            if (arr[i] + arr[i - 1] > 0) {
                tempStart = i;
            } else {
                int currentSum = findMaxSubarraySum(std::vector<int>(arr.begin() + start, arr.begin() + tempStart));
                if (currentSum == maxSum) {
                    start = tempStart;
                }
            }
        }
        if (arr[i] >= 0 && arr[i] + arr[i - 1] >= 0) {
            end = i;
        }
    }

    return {{start, end}};
}

int main() {
    std::vector<int> arr = {-2, -3, 4, -1, -2, 1, 5, -3};
    std::vector<std::pair<int, int>> result = findPeakOperationalIntervals(arr);

    std::cout << "Peak operational interval: [" << result[0].first << ", " << result[0].second << "]" << std::endl;

    return 0;
}
