public class EmergencyEvacuationRoutePlanning {
    static class Pair {
        int x, y;

        public Pair(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }

    public static void main(String[] args) {
        // Define the weighted graph
        Map<Pair, List<Pair>> graph = new HashMap<>();
        graph.put(new Pair(0, 0), Arrays.asList(new Pair(0, 1), new Pair(1, 0)));
        graph.put(new Pair(0, 1), Arrays.asList(new Pair(0, 0), new Pair(1, 1)));
        graph.put(new Pair(1, 0), Arrays.asList(new Pair(0, 1), new Pair(1, 1)));
        graph.put(new Pair(1, 1), Arrays.asList(new Pair(1, 0), new Pair(0, 1)));

        // Define the elevation and water flow rates
        Map<Pair, Integer> elevation = new HashMap<>();
        elevation.put(new Pair(0, 0), 1);
        elevation.put(new Pair(0, 1), 2);
        elevation.put(new Pair(1, 0), 3);
        elevation.put(new Pair(1, 1), 4);

        Map<Pair, Integer> waterFlowRate = new HashMap<>();
        waterFlowRate.put(new Pair(0, 0), 1);
        waterFlowRate.put(new Pair(0, 1), 2);
        waterFlowRate.put(new Pair(1, 0), 3);
        waterFlowRate.put(new Pair(1, 1), 4);

        // Initialize distances and flood exposure times
        Map<Pair, Node> nodes = new HashMap<>();
        for (Pair pair : graph.keySet()) {
            nodes.put(pair, new Node(pair.x, pair.y, elevation.get(pair), waterFlowRate.get(pair)));
        }

        // Dynamic programming to compute safest paths
        for (Pair pair : graph.keySet()) {
            for (Pair neighbor : graph.get(pair)) {
                Node node = nodes.get(pair);
                Node neighborNode = nodes.get(neighbor);

                // Calculate the new distance and flood exposure time
                int newDistance = node.distance + 1;
                int newFloodExposureTime = Math.max(node.floodExposureTime, newDistance + neighborNode.elevation - node.elevation);

                if (newDistance < neighborNode.distance) {
                    neighborNode.distance = newDistance;
                    neighborNode.floodExposureTime = newFloodExposureTime;
                }
            }
        }

        // Reconstruct the safest path with backtracking
        List<Pair> safestPath = reconstructPath(nodes, new Pair(0, 0), new Pair(0, 1));

        // Print the safest path
        for (Pair pair : safestPath) {
            System.out.println(pair);
        }
    }

    public static List<Pair> reconstructPath(Map<Pair, Node> nodes, Pair start, Pair end) {
        List<Pair> path = new ArrayList<>();
        Node currentNode = nodes.get(end);
        path.add(end);

        while (currentNode != null) {
            for (Pair pair : graph.get(currentNode.x)) {
                if (pair.y == currentNode.y - 1 && pair.x == currentNode.x - 1) {
                    currentNode = nodes.get(pair);
                    path.add(pair);
                    break;
                }
            }
        }

        Collections.reverse(path);
        return path;
    }
}
