import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        String[] docs = {"doc1", "doc2", "doc3", "doc4"};
        String[] queries = {"doc", "doc3", "doc1", "doc2", "doc4"};

        Map<String, List<String>> results = suffixArray(docs, queries);

        for (Map.Entry<String, List<String>> entry : results.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }

    public static Map<String, List<String>> suffixArray(String[] docs, String[] queries) {
        // Create suffix array for documents
        List<String> suffixDocs = new ArrayList<>();
        for (String doc : docs) {
            suffixDocs.add(doc);
        }
        suffixDocs.sort(Comparator.comparingInt(String::length));

        // Create suffix array for queries
        List<String> suffixQueries = new ArrayList<>();
        for (String query : queries) {
            suffixQueries.add(query);
        }
        suffixQueries.sort(Comparator.comparingInt(String::length));

        // Initialize result map
        Map<String, List<String>> results = new HashMap<>();

        // Iterate over queries and retrieve relevant documents
        for (String query : suffixQueries) {
            List<String> matchingDocs = new ArrayList<>();
            for (String doc : suffixDocs) {
                if (doc.startsWith(query)) {
                    matchingDocs.add(doc);
                }
            }
            Collections.sort(matchingDocs, Comparator.comparingInt(doc -> docs.indexOf(doc)));
            results.put(query, matchingDocs);
        }

        return results;
    }
}
