#include <iostream>
#include <vector>
#include <algorithm>

// Define a Task structure
struct Task {
    int priority;
    int executionTime;
    bool completed = false;
};

// BinaryHeap class to manage tasks
class BinaryHeap {
private:
    std::vector<Task> tasks;

public:
    // Add a new task to the heap
    void addTask(int priority, int executionTime) {
        Task newTask = {priority, executionTime};
        tasks.push_back(newTask);
        heapifyUp(tasks.size() - 1);
    }

    // Fetch the next task to execute
    Task getNextTask() {
        if (tasks.empty()) {
            return Task();
        }
        Task nextTask = tasks[0];
        tasks[0] = tasks.back();
        tasks.pop_back();
        heapifyDown(0);
        return nextTask;
    }

    // Remove completed tasks
    void removeCompletedTasks() {
        while (!tasks.empty() && tasks[0].completed) {
            tasks.erase(tasks.begin());
        }
    }

    // Heapify up to maintain the heap property
    void heapifyUp(int index) {
        if (index <= 0) return;
        int parentIndex = (index - 1) / 2;
        if (tasks[parentIndex].priority > tasks[index].priority) {
            std::swap(tasks[parentIndex], tasks[index]);
            heapifyUp(parentIndex);
        }
    }

    // Heapify down to maintain the heap property
    void heapifyDown(int index) {
        int smallest = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        if (left < tasks.size() && tasks[left].priority < tasks[smallest].priority) {
            smallest = left;
        }
        if (right < tasks.size() && tasks[right].priority < tasks[smallest].priority) {
            smallest = right;
        }
        if (smallest != index) {
            std::swap(tasks[index], tasks[smallest]);
            heapifyDown(smallest);
        }
    }
};

// Example usage
int main() {
    BinaryHeap heap;
    heap.addTask(1, 5);
    heap.addTask(2, 3);
    heap.addTask(3, 8);
    heap.addTask(4, 1);

    while (!heap.tasks.empty()) {
        Task task = heap.getNextTask();
        std::cout << "Task: " << task.executionTime << ", Priority: " << task.priority << ", Completed: " << (task.completed ? "true" : "false") << std::endl;
        task.completed = true;
        heap.removeCompletedTasks();
    }

    return 0;
}
