#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <stdbool.h>

#define MAX_NODES 1000
#define MAX_EDGES 2000
#define MAX_LINE_LENGTH 100

typedef struct {
    int node;
    int connection;
} Edge;

typedef struct {
    int nodes;
    Edge* edges;
} Graph;

Graph* buildGraph() {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->nodes = 0;
    graph->edges = (Edge*)malloc(MAX_EDGES * sizeof(Edge));
    return graph;
}

void addEdge(Graph* graph, int node1, int node2) {
    if (graph->nodes >= MAX_NODES) {
        printf("Network is too large.\n");
        exit(1);
    }
    graph->edges[graph->nodes].node = node1;
    graph->edges[graph->nodes].connection = node2;
    graph->edges[graph->nodes].next = graph->edges + graph->nodes + 1;
    graph->edges[graph->nodes].prev = graph->edges + graph->nodes - 1;
    graph->nodes++;
}

bool bfs(Graph* graph, int start, int target) {
    bool visited[MAX_NODES];
    int queue[MAX_NODES];
    int front = 0;
    int rear = 0;
    queue[rear++] = start;
    visited[start] = true;
    while (front < rear) {
        int node = queue[front++];
        for (int i = graph->edges[node].prev; i < graph->edges[node].next; i++) {
            int connection = graph->edges[i].connection;
            if (!visited[connection]) {
                queue[rear++] = connection;
                visited[connection] = true;
                if (connection == target) {
                    return true;
                }
            }
        }
    }
    return false;
}

int main() {
    FILE* file = fopen("network.txt", "r");
    if (!file) {
        printf("Failed to open file.\n");
        exit(1);
    }
    Graph* graph = buildGraph();
    int nodes, connections;
    fscanf(file, "%d %d", &nodes, &connections);
    for (int i = 0; i < connections; i++) {
        int node1, node2;
        fscanf(file, "%d %d", &node1, &node2);
        addEdge(graph, node1, node2);
        addEdge(graph, node2, node1);
    }
    fclose(file);
