#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// Structure to represent a node in the suffix tree
typedef struct Node {
    char data;
    struct Node* children[26];
    bool isEndOfWord;
} Node;

// Structure to represent the suffix tree
typedef struct {
    Node* root;
    char text[1000];
    int len;
} SuffixTree;

// Function to create a new node
Node* createNode(char data) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = data;
    for (int i = 0; i < 26; i++) {
        newNode->children[i] = NULL;
    }
    newNode->isEndOfWord = false;
    return newNode;
}

// Function to insert a suffix into the suffix tree
void insertSuffix(SuffixTree* tree, char* suffix) {
    Node* currentNode = tree->root;
    for (int i = 0; i < strlen(suffix); i++) {
        int index = suffix[i] - 'a';
        if (currentNode->children[index] == NULL) {
            currentNode->children[index] = createNode(suffix[i]);
        }
        currentNode = currentNode->children[index];
    }
    currentNode->isEndOfWord = true;
}

// Function to search for a substring in the suffix tree
void searchSubstring(SuffixTree* tree, char* substring, int* indices) {
    Node* currentNode = tree->root;
    for (int i = 0; i < strlen(substring); i++) {
        int index = substring[i] - 'a';
        if (currentNode->children[index] == NULL) {
            return;
        }
        currentNode = currentNode->children[index];
    }
    if (currentNode->isEndOfWord) {
        indices[0] = i;
    }
    for (int i = strlen(substring); i < tree->len; i++) {
        currentNode = currentNode->children[substring[i] - 'a'];
        if (currentNode->isEndOfWord) {
            indices[0] = i - strlen(substring) + 1;
            return;
        }
    }
}

// Function to construct the suffix tree
void constructSuffixTree(char* text, SuffixTree* tree) {
    tree->root = createNode(text[0]);
    tree->len = strlen(text);
    for (int i = 0; i < tree->len; i++) {
        insertSuffix(tree, &text[i]);
    }
}

// Function to search for multiple substrings
void searchMultipleSubstrings(SuffixTree* tree, char** substrings, int numSubstrings, int* indices) {
    for (int i = 0; i < numSubstrings; i++) {
        int tempIndices[1];
        searchSubstring(tree, substrings[i], tempIndices);
        indices[i] = tempIndices[0];
    }
}

int main() {
    char text[1000];
    printf("Enter a text: ");
    scanf("%s", text);

    SuffixTree tree;
    constructSuffixTree(text, &tree);

    char** substrings;
    int numSubstrings;
    printf("Enter the number of substrings: ");
    scanf("%d", &numSubstrings);
    substrings = (char**)malloc(numSubstrings * sizeof(char*));
    for (int i = 0; i < numSubstrings; i++) {
        printf("Enter substring %d: ", i + 1);
        scanf("%s", substrings[i]);
    }

    int indices[numSubstrings];
    searchMultipleSubstrings(&tree, substrings, numSubstrings, indices);

    printf("Starting indices of substrings:\n");
    for (int i = 0; i < numSubstrings; i++) {
        printf("%d ", indices[i]);
    }
    printf("\n");

    return 0;
}
