function bubbleSortGrades(grades) {
    let n = grades.length;
    let swaps = 0;

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n - i - 1; j++) {
            if (grades[j] > grades[j + 1]) {
                [grades[j], grades[j + 1]] = [grades[j + 1], grades[j]];
                swaps++;
            }
        }
    }

    return { sortedGrades: grades, swapCount: swaps };
}

