#include <iostream>
#include <queue>
#include <unordered_map>
#include <string>

using namespace std;

struct Node {
    char character;
    int frequency;
    Node* left;
    Node* right;

    Node(char character, int frequency) : character(character), frequency(frequency), left(nullptr), right(nullptr) {}
};

struct CompareNodes {
    bool operator()(const Node* a, const Node* b) {
        return a->frequency > b->frequency;
    }
};

string huffmanCoding(const string& text) {
    unordered_map<char, int> frequencyMap;
    for (char c : text) {
        frequencyMap[c]++;
    }

    priority_queue<Node*, vector<Node*>, CompareNodes> priorityQueue;
    for (const auto& pair : frequencyMap) {
        Node* node = new Node(pair.first, pair.second);
        priorityQueue.push(node);
    }

    while (priorityQueue.size() > 1) {
        Node* node1 = priorityQueue.top();
        priorityQueue.pop();
        Node* node2 = priorityQueue.top();
        priorityQueue.pop();

        Node* newNode = new Node('\0', node1->frequency + node2->frequency);
        newNode->left = node1;
        newNode->right = node2;

        priorityQueue.push(newNode);
    }

    Node* root = priorityQueue.top();
    unordered_map<char, string> binaryMap;
    generateBinaryMap(root, "", binaryMap);

    string encodedText;
    for (char c : text) {
        encodedText += binaryMap[c];
    }

    return encodedText;
}

void generateBinaryMap(Node* node, string currentCode, unordered_map<char, string>& binaryMap) {
    if (node->character != '\0') {
        binaryMap[node->character] = currentCode;
    }

    if (node->left != nullptr) {
        generateBinaryMap(node->left, currentCode + "0", binaryMap);
    }

    if (node->right != nullptr) {
        generateBinaryMap(node->right, currentCode + "1", binaryMap);
    }
}

int main() {
    string text = "this is an example for huffman encoding";
    string encodedText = huffmanCoding(text);
    cout << "Encoded Text: " << encodedText << endl;
    cout << "Binary Mapping:" << endl;
    for (const auto& pair : huffmanCoding::binaryMap) {
        cout << pair.first << ": " << pair.second << endl;
    }

    return 0;
}
