fn is_safe(board: &Vec<Vec<bool>>, row: usize, col: usize) -> bool {
    for i in 0..row {
        if board[i][col] {
            return false;
        }
        let mut j = col;
        while i < row && j < board.len() {
            if board[i][j] {
                return false;
            }
            i += 1;
            j += 1;
        }
    }
    true
}

fn solve_n_queens(n: usize, row: usize, board: &mut Vec<Vec<bool>>, result: &mut Vec<Vec<Vec<bool>>>>) {
    if row == n {
        let mut new_board = board.clone();
        for i in 0..n {
            for j in 0..n {
                if new_board[i][j] {
                    new_board[i][j] = false;
                }
            }
        }
        result.push(new_board);
        return;
    }
    for col in 0..n {
        if is_safe(board, row, col) {
            board[row][col] = true;
            solve_n_queens(n, row + 1, board, result);
            board[row][col] = false;
        }
    }
}

fn main() {
    let mut board = vec![vec![false; 8]; 8];
    let mut result: Vec<Vec<Vec<bool>>> = Vec::new();
    solve_n_queens(8, 0, &mut board, &mut result);
    for i in 0..result.len() {
        for j in 0..8 {
            for k in 0..8 {
                if result[i][j][k] {
                    print!("Q ");
                } else {
                    print!(" . ");
                }
            }
            println!();
        }
        println!();
    }
}
