import java.util.*;

class PerfectHashMap {
    private Map<Long, String> hashTable;
    private int size;

    public PerfectHashMap(int size) {
        this.size = size;
        this.hashTable = new HashMap<>();
    }

    public void add(String username) {
        long hashValue = hash(username);
        if (!hashTable.containsKey(hashValue)) {
            hashTable.put(hashValue, username);
        } else {
            throw new RuntimeException("Collision detected for username: " + username);
        }
    }

    public String get(String username) {
        long hashValue = hash(username);
        return hashTable.get(hashValue);
    }

    private long hash(String username) {
        long hashValue = 0;
        for (char c : username.toCharArray()) {
            hashValue = (hashValue * 31 + c) % size;
        }
        return hashValue;
    }
}

public class Main {
    public static void main(String[] args) {
        PerfectHashMap perfectHashMap = new PerfectHashMap(1000);
        List<String> usernames = Arrays.asList("user1", "user2", "user3", "user4", "user5");

        for (String username : usernames) {
            perfectHashMap.add(username);
