using namespace std;

struct Task {
    int duration;
    int priority;
};

bool compareTasks(const Task& a, const Task& b) {
    return a.priority > b.priority;
}

int main() {
    int timeLimit = 8 * 60; // Convert hours to minutes
    int tasksCount;
    cout << "Enter the number of tasks: ";
    cin >> tasksCount;

    vector<Task> tasks(tasksCount);
    for (int i = 0; i < tasksCount; ++i) {
        cout << "Enter task " << i + 1 << " duration and priority (separated by space): ";
        cin >> tasks[i].duration >> tasks[i].priority;
    }

    // Sort tasks by priority in descending order
    sort(tasks.begin(), tasks.end(), compareTasks);

    vector<bool> dp(timeLimit + 1, false);
    dp[0] = true;

    for (const auto& task : tasks) {
        for (int i = timeLimit; i >= task.duration; --i) {
            if (dp[i - task.duration]) {
                dp[i] = true;
            }
        }
    }

    int optimalSchedule = 0;
    for (int i = timeLimit; i >= 0; --i) {
        if (dp[i]) {
            optimalSchedule = i;
            break;
        }
    }

    cout << "Optimized schedule: " << optimalSchedule << " minutes" << endl;
    cout << "Selected tasks:" << endl;
    for (int i = 0; i < tasksCount; ++i) {
        if (tasks[i].duration <= optimalSchedule) {
            cout << "Task " << i + 1 << ": Duration = " << tasks[i].duration << " minutes, Priority = " << tasks[i].priority << endl;
            optimalSchedule -= tasks[i].duration;
        }
    }

    return 0;
}
