use std::collections::{BinaryHeap, VecDeque};

struct Graph {
    nodes: usize,
    edges: Vec<(usize, usize, usize)>,
}

impl Graph {
    fn new(nodes: usize) -> Self {
        Graph {
            nodes,
            edges: Vec::new(),
        }
    }

    fn add_edge(&mut self, u: usize, v: usize, weight: usize) {
        self.edges.push((u, v, weight));
    }

    fn prim_mst(&self) -> Vec<(usize, usize, usize)> {
        let mut visited = vec![false; self.nodes + 1];
        let mut mst = Vec::new();

        let mut pq = BinaryHeap::new();
        pq.push((0, 0, 0));

        while let Some((weight, u, v)) = pq.pop() {
            if visited[u] || visited[v] {
                continue;
            }

            visited[u] = true;
            visited[v] = true;

            mst.push((u, v, weight));

            for (u2, v2, weight2) in &self.edges {
                if *u2 == u || *v2 == u || *u2 == v || *v2 == v {
                    continue;
                }

                if !visited[*u2] && weight2 < weight {
                    pq.push((weight2, *u2, *v2));
                }
            }
        }

        mst
    }
}

fn main() {
    let mut graph = Graph::new(5);
    graph.add_edge(1, 0, 4);
    graph.add_edge(0, 2, 2);
    graph.add_edge(1, 3, 5);
    graph.add_edge(3, 4, 3);

    let mst = graph.prim_mst();

    for (u, v, weight) in mst {
        println!("Edge: ({}, {}), Weight: {}", u, v, weight);
    }
}
