class BloomFilter {
  constructor(size, hashFunctions) {
    this.size = size;
    this.hashFunctions = hashFunctions;
    this.bitArray = new Array(size).fill(false);
  }

  _hash(item, seed) {
    return (item + seed) % this.size;
  }

  add(item) {
    for (let seed = 0; seed < this.hashFunctions; seed++) {
      const index = this._hash(item, seed);
      this.bitArray[index] = true;
    }
  }

  exists(item) {
    for (let seed = 0; seed < this.hashFunctions; seed++) {
      const index = this._hash(item, seed);
      if (!this.bitArray[index]) return false;
    }
    return true;
  }
}

