void createGraph(int **graph, int vertices) {
    for (int i = 0; i < vertices; i++) {
        for (int j = 0; j < vertices; j++) {
            graph[i][j] = 0;
        }
    }
}

// Function to implement Bellman-Ford algorithm
void bellmanFord(int **graph, int vertices, int startVertex) {
    int **dist = (int **)malloc(vertices * sizeof(int *));
    for (int i = 0; i < vertices; i++) {
        dist[i] = (int *)malloc(vertices * sizeof(int));
    }

    // Initialize distances with infinity
    for (int i = 0; i < vertices; i++) {
        for (int j = 0; j < vertices; j++) {
            dist[i][j] = INT_MAX;
        }
        dist[i][i] = 0;
    }

    // Relax edges
    for (int i = 0; i < vertices - 1; i++) {
        for (int u = 0; u < vertices; u++) {
            for (int v = 0; v < vertices; v++) {
                if (graph[u][v] != 0 && dist[u][v] > dist[u][v] + graph[u][v]) {
                    dist[u][v] = dist[u][v] + graph[u][v];
                }
            }
        }
    }

    // Check for negative-weight cycles
    for (int u = 0; u < vertices; u++) {
        for (int v = 0; v < vertices; v++) {
            if (graph[u][v] != 0 && dist[u][v] > dist[u][v] + graph[u][v]) {
                printf("Graph contains a negative weight cycle.\n");
                return;
            }
        }
    }

    // Print shortest distances
    printf("Vertex\t\tDistance from Source\n");
    for (int i = 0; i < vertices; i++) {
        printf("%d\t\t%d\n", i, dist[startVertex][i]);
    }
}

