use std::collections::BinaryHeap;
use std::collections::HashMap;
use std::collections::HashSet;

struct DisjointSet {
    parent: HashMap<i32, i32>,
    rank: HashMap<i32, i32>,
}

impl DisjointSet {
    fn new(n: i32) -> Self {
        Self {
            parent: HashMap::new(),
            rank: HashMap::new(),
        }
    }

    fn find(&mut self, x: i32) -> i32 {
        if self.parent.get(&x).unwrap() != &x {
            self.parent.insert(x, self.find(self.parent[&x].clone()));
        }
        self.parent[&x].clone()
    }

    fn union(&mut self, x: i32, y: i32) {
        let x_root = self.find(x);
        let y_root = self.find(y);

        if x_root != y_root {
            if self.rank.get(&x_root).unwrap() > self.rank.get(&y_root).unwrap() {
                self.parent.insert(y_root, x_root);
            } else if self.rank.get(&x_root).unwrap() < self.rank.get(&y_root).unwrap() {
                self.parent.insert(x_root, y_root);
            } else {
                self.parent.insert(y_root, x_root);
                self.rank.insert(x_root, self.rank.get(&x_root).unwrap() + 1);
            }
        }
    }
}

fn kruskal(edges: Vec<(i32, i32, i32)>) -> Vec<(i32, i32, i32)> {
    let mut mst = Vec::new();
    let mut disjoint_set = DisjointSet::new(edges.len() as i32);
    let mut edges_heap = BinaryHeap::new();

    for edge in edges {
        edges_heap.push(edge);
    }

    while let Some(edge) = edges_heap.pop() {
        if disjoint_set.find(edge.0) != disjoint_set.find(edge.1) {
            mst.push(edge);
            disjoint_set.union(edge.0, edge.1);
        }
    }

    mst
}

fn main() {
    let edges = vec![
        (1, 2, 10),
        (2, 3, 6),
        (1, 3, 5),
        (3, 4, 8),
        (1, 4, 7),
    ];

    let mst = kruskal(edges);
    for edge in mst {
        println!("({},{},{})", edge.0, edge.1, edge.2);
    }
}
