import java.util.*;

class HashTable {
    private static final int INITIAL_CAPACITY = 10;
    private static final double LOAD_FACTOR_THRESHOLD = 0.75;
    private static final Random random = new Random();

    private int size;
    private List<Map.Entry<String, Object>>[] table;
    private int threshold;

    public HashTable() {
        this(INITIAL_CAPACITY);
    }

    public HashTable(int capacity) {
        this.size = 0;
        this.threshold = (int) (capacity * LOAD_FACTOR_THRESHOLD);
        this.table = new List[capacity];
        for (int i = 0; i < capacity; i++) {
            this.table[i] = new ArrayList<>();
        }
    }

    public void put(String key, Object value) {
        int index = hash(key) % table.length;
        for (Map.Entry<String, Object> entry : table[index]) {
            if (entry.getKey().equals(key)) {
                entry.setValue(value);
                return;
            }
        }
        table[index].add(new AbstractMap.SimpleEntry<>(key, value));
        resizeIfNecessary();
    }

    public Object get(String key) {
        int index = hash(key) % table.length;
        for (Map.Entry<String, Object> entry : table[index]) {
            if (entry.getKey().equals(key)) {
                return entry.getValue();
            }
        }
        return null;
    }

    public void delete(String key) {
        int index = hash(key) % table.length;
        table[index].removeIf(entry -> entry.getKey().equals(key));
        resizeIfNecessary();
    }

    private int hash(String key) {
        int prime = 31;
        int result = 1;
        for (char c : key.toCharArray()) {
            result = (int) ((long) result * prime + c);
        }
        return result;
    }

    private void resizeIfNecessary() {
        if (size >= threshold) {
            int newCapacity = table.length * 2;
            List<Map.Entry<String, Object>>[] newTable = new List[newCapacity];
            for (int i = 0; i < newCapacity; i++) {
                newTable[i] = new ArrayList<>();
            }
            for (List<Map.Entry<String, Object>> list : table) {
                for (Map.Entry<String, Object> entry : list) {
                    int newIndex = hash(entry.getKey()) % newCapacity;
                    newTable[newIndex].add(entry);
                }
            }
            table = newTable;
        }
    }

    public void printStatistics() {
        System.out.println("Size: " + size);
        System.out.println("Load Factor: " + (double) size / table.length);
        System.out.println("Threshold: " + threshold);
    }
}

public class Main {
    public static void main(String[] args) {
        HashTable hashTable = new HashTable();
        hashTable.put("apple", 5);
        hashTable.put("banana", 10);
        hashTable.put("orange", 15);
        hashTable.printStatistics();
        System.out.println(hashTable.get("banana"));
        hashTable.delete("apple");
        hashTable.printStatistics();
    }
}
