    bits: Vec<bool>,
}

impl BitSet {
    fn new(size: usize) -> Self {
        BitSet { size, bits: vec![false; size] }
    }

    fn get(&self, index: usize) -> bool {
        self.bits[index]
    }

    fn set(&mut self, index: usize) {
        self.bits[index] = true;
    }

    fn clear(&mut self, index: usize) {
        self.bits[index] = false;
    }

    fn count_set(&self) -> usize {
        self.bits.iter().filter(|&x| *x).count()
    }
}

fn max_tasks(tasks: Vec<Task>, max_requirements: usize) -> usize {
    let mut available_requirements = BitSet::new(max_requirements);
    let mut selected_tasks = Vec::new();
    let mut selected_requirements = HashMap::new();

    tasks.sort_by_key(|task| task.requirements.len());

    for task in tasks {
        let mut task_requirements = HashSet::new();
        for requirement in task.requirements {
            if available_requirements.get(requirement as usize) {
                task_requirements.insert(requirement);
                available_requirements.set(requirement as usize);
