    void randomLevelIncrease() {
        if (rand.nextInt(2) == 0) {
            maxLevel++;
            for (int i = 0; i < head.length; i++) {
                Node node = head[i];
                while (node.next[maxLevel - 1] != null) {
                    node = node.next[maxLevel - 1];
                }
                node.next[maxLevel] = new Node(0);
            }
        }
    }

    void randomLevelDecrease() {
        if (maxLevel > 1 && rand.nextInt(2) == 0) {
            maxLevel--;
            for (int i = 0; i < head.length; i++) {
                Node node = head[i];
                while (node.next[maxLevel - 1] != null) {
                    node = node.next[maxLevel - 1];
                }
                node.next[maxLevel] = null;
            }
