class BinaryTree {
    constructor(root = null) {
        this.root = root;
    }

    binaryLifting() {
        this.size = {};
        this.parent = {};
        this.buildTree(this.root, null);
    }

    buildTree(node, parent) {
        if (node === null) {
            return;
        }

        this.size[node.val] = 1;
        this.parent[node.val] = parent;
        this.buildTree(node.left, node.val);
        this.buildTree(node.right, node.val);
    }

    find(node, target) {
        if (node === null) {
            return false;
        }

        if (node.val === target) {
            return true;
        }

        let left = this.find(node.left, target);
        let right = this.find(node.right, target);

        if (left || right) {
            return left || right;
        }

        return false;
    }

    binaryLiftingLCA(node1, node2) {
        if (node1 === null || node2 === null) {
            return null;
        }

        let path1 = this.path(node1, node2);
        let path2 = this.path(node2, node1);

        if (!path1 || !path2) {
            return null;
        }

        let i = 0;
        while (i < path1.length && i < path2.length && path1[i] === path2[i]) {
            i++;
        }

        return path1[i - 1];
    }

    path(node, target) {
        let path = [];

        while (node !== null) {
            path.push(node.val);
            node = this.parent[node.val];
        }

        if (!this.find(node, target)) {
            return null;
        }

        for (let i = path.length - 1; i >= 0; i--) {
            if (path[i] === target) {
                return path.slice(0, i + 1);
            }
        }
    }
}

