// Node structure for the doubly linked list
struct Node {
    std::string title;
    Node* next;
    Node* prev;
};

// DoublyLinkedList class
class DoublyLinkedList {
private:
    Node* head;
    Node* tail;
    int size;

public:
    DoublyLinkedList() : head(nullptr), tail(nullptr), size(0) {}

    // Destructor to free memory
    ~DoublyLinkedList() {
        while (head) {
            Node* temp = head;
            head = head->next;
            delete temp;
        }
    }

    // Add a new song to the end of the playlist
    void addSong(const std::string& title) {
        if (size == 50) {
            std::cout << "Playlist is full. Cannot add more songs." << std::endl;
            return;
        }

        Node* newNode = new Node();
        newNode->title = title;
        newNode->next = nullptr;
        newNode->prev = tail;
        if (tail) {
            tail->next = newNode;
        } else {
            head = newNode;
        }
        tail = newNode;
        size++;
    }

    // Remove a song from the playlist
    void removeSong(const std::string& title) {
        if (head == nullptr) {
            std::cout << "Playlist is empty. Cannot remove songs." << std::endl;
            return;
        }

        if (head->title == title) {
            Node* temp = head;
            head = head->next;
            delete temp;
            if (head) {
                head->prev = nullptr;
            } else {
                tail = nullptr;
            }
            size--;
            return;
        }

        Node* current = head;
        while (current->next) {
            if (current->next->title == title) {
                Node* temp = current->next;
                current->next = current->next->next;
                if (current->next) {
                    current->next->prev = current;
                } else {
                    tail = current;
                }
                delete temp;
                size--;
                return;
            }
            current = current->next;
        }

        std::cout << "Song not found in the playlist." << std::endl;
    }

    // Display all songs in the playlist
    void displayPlaylist() {
        if (head == nullptr) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }

        Node* current = head;
        while (current) {
            std::cout << current->title << std::endl;
            current = current->next;
        }
    }

    // Sort the playlist alphabetically by title
    void sortPlaylist() {
        if (head == nullptr) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }

        std::vector<std::string> songs;
        Node* current = head;
        while (current) {
            songs.push_back(current->title);
            current = current->next;
        }

        std::sort(songs.begin(), songs.end());

        current = head;
        while (current) {
            current->title = songs[current->title];
            current = current->next;
        }
    }

    // Navigate through the playlist in both directions
    void navigatePlaylist() {
        if (head == nullptr) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }

        Node* current = head;
        while (current) {
            std::cout << "Title: " << current->title << std::endl;
            std::cout << "Next: ";
            if (current->next) {
                std::cout << current->next->title << std::endl;
            } else {
                std::cout << "None" << std::endl;
            }
            std::cout << "Prev: ";
            if (current->prev) {
                std::cout << current->prev->title << std::endl;
            } else {
                std::cout << "None" << std::endl;
            }
            std::cout << std::endl;
            current = current->next;
        }
    }
};

