    while (true) {
        std::cout << "1. Add song" << std::endl;
        std::cout << "2. Remove song" << std::endl;
        std::cout << "3. Display playlist" << std::endl;
        std::cout << "4. Sort playlist" << std::endl;
        std::cout << "5. Navigate playlist" << std::endl;
        std::cout << "6. Exit" << std::endl;
