use std::collections::HashSet;

pub struct DisjointSet {
    parent: Vec<usize>,
    rank: Vec<usize>,
    components: HashSet<usize>,
}

impl DisjointSet {
    pub fn new(n: usize) -> Self {
        let mut parent = vec![0; n];
        let mut rank = vec![0; n];
        let mut components = HashSet::new();

        for i in 0..n {
            parent[i] = i;
            components.insert(i);
        }

        DisjointSet { parent, rank, components }
    }

    pub fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    pub fn union(&mut self, x: usize, y: usize) {
        let x_root = self.find(x);
        let y_root = self.find(y);

        if x_root == y_root {
            return;
        }

        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else if self.rank[x_root] > self.rank[y_root] {
            self.parent[y_root] = x_root;
        } else {
            self.parent[y_root] = x_root;
            self.rank[x_root] += 1;
        }

        self.components.remove(&x_root);
        self.components.remove(&y_root);
        self.components.insert(self.find(x_root));
    }
}

fn main() {
    let mut ds = DisjointSet::new(10);
    ds.union(1, 2);
    ds.union(2, 3);
    ds.union(4, 5);
    ds.union(6, 7);
    ds.union(8, 9);

    println!("Components: {:?}", ds.components);
}
