#include <iostream>
#include <vector>
#include <string>
#include <stdexcept>

// Function to validate postfix notation
bool isValidPostfix(const std::string& expression) {
    std::vector<char> stack;
    for (char c : expression) {
        if (c == ' ') continue;
        if (c == '+' || c == '-' || c == '*' || c == '/') {
            if (stack.empty()) return false;
            char operand2 = stack.back();
            stack.pop_back();
            char operand1 = stack.back();
            stack.pop_back();
            if (c == '+') stack.push_back(operand1 + operand2);
            else if (c == '-') stack.push_back(operand1 - operand2);
            else if (c == '*') stack.push_back(operand1 * operand2);
            else if (c == '/') stack.push_back(operand1 / operand2);
        } else {
            stack.push_back(c);
        }
    }
    return stack.empty();
}

// Function to evaluate postfix expression using stack
double evaluatePostfix(const std::string& expression) {
    std::vector<double> stack;
    for (char c : expression) {
        if (c == ' ') continue;
        if (c == '+' || c == '-' || c == '*' || c == '/') {
            if (stack.size() < 2) throw std::invalid_argument("Invalid postfix expression");
            double operand2 = stack.back();
            stack.pop_back();
            double operand1 = stack.back();
            stack.pop_back();
            if (c == '+') stack.push_back(operand1 + operand2);
            else if (c == '-') stack.push_back(operand1 - operand2);
            else if (c == '*') stack.push_back(operand1 * operand2);
            else if (c == '/') stack.push_back(operand1 / operand2);
        } else {
            stack.push_back(c - '0'); // Convert character to integer
        }
    }
    if (stack.size() > 1) throw std::invalid_argument("Invalid postfix expression");
    return stack.back();
}

int main() {
    std::string expression;
    std::cout << "Enter a postfix expression: ";
    std::getline(std::cin, expression);

    if (!isValidPostfix(expression)) {
        std::cout << "Invalid postfix expression." << std::endl;
        return 1;
    }

    double result = evaluatePostfix(expression);
    std::cout << "Result: " << result << std::endl;

    return 0;
}
