    for (let i = 0; i < sortedGrades.length; i++) {
        let minIndex = i;
        for (let j = i + 1; j < sortedGrades.length; j++) {
            if (sortedGrades[j] < sortedGrades[minIndex]) {
                minIndex = j;
            }
        }
        [sortedGrades[i], sortedGrades[minIndex]] = [sortedGrades[minIndex], sortedGrades[i]];
    }
    return sortedGrades;
