class Node:
    def __init__(self, key, degree):
        self.key = key
        self.degree = degree
        self.child = []
        self.parent = None
        self.mark = 0

class FibonacciHeap:
    def __init__(self):
        self.min = None
        self.size = 0
        self.nodes = {}

    def insert(self, key):
        node = Node(key, 0)
        self.nodes[key] = node
        if not self.min or node.key < self.min.key:
            self.min = node
        self.size += 1
        self._merge()

    def extract_min(self):
        if not self.min:
            return None
        min_node = self.min
        if self.min.child:
            self._cut(min_node)
        for child in min_node.child:
            self._merge(child)
        del self.nodes[min_node.key]
        if not self.nodes:
            self.min = None
        else:
            min_node = min(self.nodes.values(), key=lambda x: x.key)
            self.min = min_node
        self.size -= 1
        return min_node.key

    def _merge(self, node):
        if not node.mark:
            self.nodes[node.key].mark += 1
            if node.parent:
                self._cut(node)
            else:
                if not self.min or node.key < self.min.key:
                    self.min = node
        for child in node.child:
            self._merge(child)

    def _cut(self, node):
        if node.parent:
            parent = node.parent
            self.nodes[parent.key].child.remove(node)
            if not node.child:
                del self.nodes[node.key]
            parent.degree += 1
            if parent.degree == 1:
                self._cut(parent)

    def merge(self, other):
        for node in other.nodes.values():
            self.insert(node.key)

    def print_min(self):
        if self.min:
            print(self.min.key)
        else:
            print("Heap is empty")

# Example usage
