use std::collections::{HashMap, VecDeque};
use std::cmp::Reverse;

struct Graph {
    adjacency_list: HashMap<String, Vec<(String, i64)>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            adjacency_list: HashMap::new(),
        }
    }

    fn add_edge(&mut self, src: &str, dest: &str, delay: i64) {
        self.adjacency_list.entry(src.to_string()).or_insert(Vec::new()).push((dest.to_string(), delay));
    }

    fn bellman_ford(&self, source: &str) -> Result<HashMap<String, i64>, String> {
        let mut distances = HashMap::new();
        let mut predecessors = HashMap::new();

        for (node, neighbors) in &self.adjacency_list {
            distances.insert(node.to_string(), std::i64::MAX);
            predecessors.insert(node.to_string(), None);
        }
        distances.insert(source.to_string(), 0);

        let mut queue = VecDeque::new();
        queue.push_back(source.to_string());

        while let Some(node) = queue.pop_front() {
            for (neighbor, delay) in &self.adjacency_list[&node] {
                let distance = distances.get(node).unwrap() + delay;
                if distance < distances.get(neighbor).unwrap() {
                    distances.insert(neighbor.to_string(), distance);
                    predecessors.insert(neighbor.to_string(), Some(node.to_string()));
                    queue.push_back(neighbor.to_string());
                }
            }
        }

        for (node, neighbors) in &self.adjacency_list {
            for (neighbor, delay) in neighbors {
                if distances.get(node).unwrap() + delay < distances.get(neighbor).unwrap() {
                    return Err(format!("Negative weight cycle detected: {} -> {} -> {}", node, neighbor, delay));
                }
            }
        }

        Ok(distances)
    }
}

fn main() {
    let mut graph = Graph::new();
    graph.add_edge("A", "B", -1);
    graph.add_edge("B", "C",  4);
    graph.add_edge("A", "C",  1);
    graph.add_edge("C", "B",  2);
    graph.add_edge("C", "D",  5);
    graph.add_edge("D", "A", -4);

    let shortest_distances = graph.bellman_ford("A").unwrap();

    for (node, distance) in shortest_distances {
        println!("Shortest distance from A to {}: {}", node, distance);
    }
}
