class Graph {
    constructor(vertices) {
        this.V = vertices;
        this.graph = [];
    }

    addEdge(u, v, w) {
        this.graph.push([u, v, w]);
    }

    find(parent, i) {
        if (parent[i] === i)
            return i;
        return this.find(parent, parent[i]);
    }

    union(parent, rank, x, y) {
        let xroot = this.find(parent, x);
        let yroot = this.find(parent, y);

        if (rank[xroot] < rank[yroot])
            parent[xroot] = yroot;
        else if (rank[xroot] > rank[yroot])
            parent[yroot] = xroot;
        else {
            parent[yroot] = xroot;
            rank[xroot]++;
        }
    }

    kruskalMST() {
        let result = [];
        let i = 0;
        let e = 0;
        this.graph.sort((a, b) => a[2] - b[2]);
        let parent = [];
        let rank = [];

        for (let node = 0; node < this.V; node++) {
            parent.push(node);
            rank.push(0);
        }

        while (e < this.V - 1) {
            let [u, v, w] = this.graph[i];
            i++;
            let x = this.find(parent, u);
            let y = this.find(parent, v);

            if (x !== y) {
                e++;
                result.push([u, v, w]);
                this.union(parent, rank, x, y);
            }
        }

        let minimumCost = 0;
        console.log("Edges in the constructed MST");
        for (let [u, v, weight] of result) {
            minimumCost += weight;
            console.log(`${u} -- ${v} == ${weight}`);
        }
        console.log(`Minimum Spanning Tree ${minimumCost}`);
    }
}

