function mergeSort(students) {
    if (students.length <= 1) return students;

    const mid = Math.floor(students.length / 2);
    const left = mergeSort(students.slice(0, mid));
    const right = mergeSort(students.slice(mid));

    return merge(left, right);
}

function merge(left, right) {
    const result = [];
    let i = 0;
    let j = 0;

    while (i < left.length && j < right.length) {
        if (left[i].score > right[j].score || (left[i].score === right[j].score && left[i].name < right[j].name)) {
            result.push(left[i]);
            i++;
        } else {
            result.push(right[j]);
            j++;
        }
    }

    return result.concat(left.slice(i)).concat(right.slice(j));
}

class Student {
