class Exercise {
    constructor(name, duration, calories) {
        this.name = name;
        this.duration = duration;
        this.calories = calories;
        this.ratio = calories / duration;
    }
}

class FitnessPlan {
    constructor(exercises) {
        this.exercises = exercises;
        this.schedule = [];
    }

    optimizeSchedule() {
        this.exercises.sort((a, b) => b.ratio - a.ratio);

        for (let exercise of this.exercises) {
            if (this.schedule.reduce((total, current) => total + current.duration, 0) + exercise.duration <= 60) {
                this.schedule.push(exercise);
            } else {
                break;
            }
        }
    }

    printSchedule() {
        for (let exercise of this.schedule) {
            console.log(`Exercise: ${exercise.name}, Duration: ${exercise.duration} minutes, Calories: ${exercise.calories}`);
        }
    }
}

function main() {
    let exercises = [
        new Exercise('Running', 30, 400),
        new Exercise('Swimming', 45, 500),
        new Exercise('Cycling', 20, 300),
        new Exercise('Yoga', 30, 100),
        new Exercise('Weightlifting', 45, 700),
    ];

    let plan = new FitnessPlan(exercises);
    plan.optimizeSchedule();
    plan.printSchedule();
}

