#include <vector>
#include <iostream>

int climbStairs(int n) {
    if (n == 1) return 1;
    if (n == 2) return 2;

    std::vector<int> dp(n + 1, 0);
    dp[1] = 1;
    dp[2] = 2;

    for (int i = 3; i <= n; i++) {
        dp[i] = dp[i - 1] + dp[i - 2];
    }

    return dp[n];
}

int main() {
    int n;
    std::cout << "Enter the number of stairs: ";
    std::cin >> n;
    std::cout << "Number of unique ways to reach the top: " << climbStairs(n) << std::endl;
    return 0;
}
